class Solution:
    def countUnguarded(self, m, n, guards, walls):
        EMPTY, GUARD, WALL, SEEN = 0, 1, 2, 3
        grid = [[EMPTY] * n for _ in range(m)]
        for r, c in walls:
            grid[r][c] = WALL
        for r, c in guards:
            grid[r][c] = GUARD
        guard_set = {(r, c) for r, c in guards}
        wall_set = {(r, c) for r, c in walls}
        seen = set()
        for gr, gc in guards:
            for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                r, c = gr + dr, gc + dc
                while 0 <= r < m and 0 <= c < n and (r, c) not in wall_set and (r, c) not in guard_set:
                    seen.add((r, c))
                    r += dr
                    c += dc
        count = 0
        for r in range(m):
            for c in range(n):
                if (r, c) not in guard_set and (r, c) not in wall_set and (r, c) not in seen:
                    count += 1
        return count

