        grid = [[EMPTY] * n for _ in range(m)]
        for r, c in walls:
            grid[r][c] = WALL
        for r, c in guards:
            grid[r][c] = GUARD
        for gr, gc in guards:
            for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                r, c = gr + dr, gc + dc
                while 0 <= r < m and 0 <= c < n and grid[r][c] in (EMPTY, SEEN):
                    grid[r][c] = SEEN
                    r += dr
                    c += dc
        return sum(1 for row in grid for v in row if v == EMPTY)

