var countUnguarded = function(m, n, guards, walls) {
    const EMPTY = 0, GUARD = 1, WALL = 2, SEEN = 3;
    const grid = Array.from({ length: m }, () => new Array(n).fill(EMPTY));
    for (const [r, c] of walls) grid[r][c] = WALL;
    for (const [r, c] of guards) grid[r][c] = GUARD;
    const dirs = [[1, 0], [-1, 0], [0, 1], [0, -1]];
    for (const [gr, gc] of guards) {
        for (const [dr, dc] of dirs) {
            let r = gr + dr, c = gc + dc;
            while (r >= 0 && r < m && c >= 0 && c < n && (grid[r][c] === EMPTY || grid[r][c] === SEEN)) {
                grid[r][c] = SEEN;
                r += dr;
                c += dc;
            }
        }
    }
    let count = 0;
    for (let r = 0; r < m; r++) {
        for (let c = 0; c < n; c++) {
            if (grid[r][c] === EMPTY) count++;
        }
    }
    return count;
};
